exercise.solution_code:
#include <iostream>

int g_total { 0 };

void addToTotal(int value) {
    g_total += value;
}

int main() {
    int v1{}, v2{}, v3{}, v4{};
    std::cin >> v1 >> v2 >> v3 >> v4;

    addToTotal(v1);
    addToTotal(v2);
    addToTotal(v3);
    addToTotal(v4);

    std::cout << "Total: " << g_total << '\n';
    return 0;
}
